function DrawTreemap() {
  const { Treemap } = components;
  const dimensionField = "dimension_column";
  const measureField = "measure_column";
  const chartData = {
    name: "root",
    children: data.map((item) => ({
      name: item[dimensionField],
      value: item[measureField],
      ...item
    }))
  };
  const config = {
    data: chartData,
    colorField: "name",
    label: {
      fields: [dimensionField]
    }
  };
  return <div><Treemap {...config} /></div>;
}
